import{_ as s,c as t,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Mettre à Jour les Skills : Garder vos Skills à Jour | opencode-openskills","description":"Apprenez à utiliser la commande OpenSkills update pour actualiser les skills installés. Prend en charge la mise à jour globale de tous les skills ou de skills spécifiques, maîtrisez les différences de mise à jour entre les chemins locaux et les dépôts git, et gardez vos skills à la dernière version.","frontmatter":{"title":"Mettre à Jour les Skills : Garder vos Skills à Jour | opencode-openskills","sidebarTitle":"Mettre à Jour les Skills en un Clic","subtitle":"Mettre à Jour les Skills : Garder vos Skills à Jour","description":"Apprenez à utiliser la commande OpenSkills update pour actualiser les skills installés. Prend en charge la mise à jour globale de tous les skills ou de skills spécifiques, maîtrisez les différences de mise à jour entre les chemins locaux et les dépôts git, et gardez vos skills à la dernière version.","tags":["skills","update","git"],"prerequisite":["start-installation","start-first-skill"],"order":5},"headers":[],"relativePath":"fr/numman-ali/openskills/platforms/update-skills/index.md","filePath":"fr/numman-ali/openskills/platforms/update-skills/index.md"}'),a={name:"fr/numman-ali/openskills/platforms/update-skills/index.md"};function r(o,e,n,d,u,p){return l(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="mettre-a-jour-les-skills-garder-vos-skills-synchronises-avec-le-depot-source" tabindex="-1">Mettre à jour les Skills : Garder vos Skills Synchronisés avec le Dépôt Source <a class="header-anchor" href="#mettre-a-jour-les-skills-garder-vos-skills-synchronises-avec-le-depot-source" aria-label="Permalink to &quot;Mettre à jour les Skills : Garder vos Skills Synchronisés avec le Dépôt Source&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que Vous Apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que Vous Apprendrez&quot;">​</a></h2><p>Cette leçon vous apprend à garder les skills OpenSkills toujours à jour. Grâce à la commande OpenSkills update, vous pourrez :</p><ul><li>Mettre à jour tous les skills installés en un seul clic</li><li>Mettre à jour uniquement quelques skills spécifiques</li><li>Comprendre les différences de mise à jour selon les sources d&#39;installation</li><li>Diagnostiquer les causes des échecs de mise à jour</li></ul><h2 id="votre-probleme-actuel" tabindex="-1">Votre Problème Actuel <a class="header-anchor" href="#votre-probleme-actuel" aria-label="Permalink to &quot;Votre Problème Actuel&quot;">​</a></h2><p>Les dépôts de skills sont constamment mis à jour — les auteurs peuvent avoir corrigé des bugs, ajouté de nouvelles fonctionnalités, ou amélioré la documentation. Mais les skills que vous avez installés sont toujours à l&#39;ancienne version.</p><p>Vous avez peut-être déjà rencontré ces situations :</p><ul><li>La documentation du skill indique &quot;prend en charge cette fonctionnalité&quot;, mais votre agent IA dit qu&#39;il ne sait pas</li><li>Le skill a de meilleurs messages d&#39;erreur, mais vous voyez toujours les anciens</li><li>Un bug présent lors de l&#39;installation a été corrigé, mais vous en êtes encore affecté</li></ul><p><strong>Supprimer et réinstaller à chaque fois est trop fastidieux</strong> — vous avez besoin d&#39;une méthode de mise à jour efficace.</p><h2 id="quand-utiliser-cette-commande" tabindex="-1">Quand Utiliser Cette Commande <a class="header-anchor" href="#quand-utiliser-cette-commande" aria-label="Permalink to &quot;Quand Utiliser Cette Commande&quot;">​</a></h2><p>Scénarios typiques d&#39;utilisation de la commande <code>update</code> :</p><table tabindex="0"><thead><tr><th>Scénario</th><th>Action</th></tr></thead><tbody><tr><td>Découvrir qu&#39;un skill a une mise à jour</td><td>Exécuter <code>openskills update</code></td></tr><tr><td>Mettre à jour seulement quelques skills</td><td><code>openskills update skill1,skill2</code></td></tr><tr><td>Tester un skill en développement local</td><td>Mettre à jour depuis le chemin local</td></tr><tr><td>Mettre à jour depuis un dépôt GitHub</td><td>Cloner automatiquement le dernier code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Recommandation de Fréquence de Mise à Jour</p><ul><li><strong>Skills communautaires</strong> : Mettre à jour une fois par mois pour obtenir les dernières améliorations</li><li><strong>Skills que vous développez</strong> : Mettre à jour manuellement après chaque modification</li><li><strong>Skills installés depuis un chemin local</strong> : Mettre à jour après chaque modification de code</li></ul></div><h2 id="🎒-preparatifs" tabindex="-1">🎒 Préparatifs <a class="header-anchor" href="#🎒-preparatifs" aria-label="Permalink to &quot;🎒 Préparatifs&quot;">​</a></h2><p>Avant de commencer, assurez-vous d&#39;avoir terminé :</p><ul><li>[x] OpenSkills installé (voir <a href="./../../start/installation/">Installer OpenSkills</a>)</li><li>[x] Au moins un skill installé (voir <a href="./../../start/first-skill/">Installer votre Premier Skill</a>)</li><li>[x] Si installé depuis GitHub, assurez-vous d&#39;avoir une connexion internet</li></ul><h2 id="concept-central" tabindex="-1">Concept Central <a class="header-anchor" href="#concept-central" aria-label="Permalink to &quot;Concept Central&quot;">​</a></h2><p>Le mécanisme de mise à jour d&#39;OpenSkills est très simple :</p><p><strong>Enregistrer les informations de source lors de chaque installation → Recopier depuis la source originale lors de la mise à jour</strong></p><div class="info custom-block"><p class="custom-block-title">Pourquoi une réinstallation est-elle nécessaire ?</p><p>Les skills de l&#39;ancienne version (installés sans enregistrer la source) ne peuvent pas être mis à jour. Dans ce cas, vous devez réinstaller une fois, et OpenSkills mémorisera la source. Après cela, les mises à jour automatiques seront possibles.</p></div><p><strong>Méthodes de mise à jour pour trois sources d&#39;installation</strong> :</p><table tabindex="0"><thead><tr><th>Type de Source</th><th>Méthode de Mise à Jour</th><th>Scénario Applicable</th></tr></thead><tbody><tr><td><strong>Chemin local</strong></td><td>Copier directement depuis le chemin local</td><td>Développer vos propres skills</td></tr><tr><td><strong>Dépôt git</strong></td><td>Cloner le dernier code dans un répertoire temporaire</td><td>Installer depuis GitHub/GitLab</td></tr><tr><td><strong>GitHub shorthand</strong></td><td>Convertir en URL complète puis cloner</td><td>Installer depuis un dépôt GitHub officiel</td></tr></tbody></table><p>Lors de la mise à jour, les skills sans métadonnées de source seront ignorés, et les noms des skills nécessitant une réinstallation seront listés.</p><h2 id="suivez-le-guide" tabindex="-1">Suivez le Guide <a class="header-anchor" href="#suivez-le-guide" aria-label="Permalink to &quot;Suivez le Guide&quot;">​</a></h2><h3 id="etape-1-voir-les-skills-installes" tabindex="-1">Étape 1 : Voir les Skills Installés <a class="header-anchor" href="#etape-1-voir-les-skills-installes" aria-label="Permalink to &quot;Étape 1 : Voir les Skills Installés&quot;">​</a></h3><p>Vérifiez d&#39;abord quels skills peuvent être mis à jour :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Liste des skills installés, incluant le nom, la description et l&#39;étiquette d&#39;emplacement d&#39;installation (project/global)</p><h3 id="etape-2-mettre-a-jour-tous-les-skills" tabindex="-1">Étape 2 : Mettre à Jour Tous les Skills <a class="header-anchor" href="#etape-2-mettre-a-jour-tous-les-skills" aria-label="Permalink to &quot;Étape 2 : Mettre à Jour Tous les Skills&quot;">​</a></h3><p>La méthode la plus simple consiste à mettre à jour tous les skills installés :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Mise à jour des skills un par un, chaque skill affichant le résultat de la mise à jour</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Skipped: my-old-skill (no source metadata; re-install once to enable updates)</span></span>
<span class="line"><span>Summary: 2 updated, 1 skipped (3 total)</span></span></code></pre></div><details class="details custom-block"><summary>Signification des Skills Ignorés</summary><p>Si vous voyez <code>Skipped: xxx (no source metadata)</code>, cela signifie que ce skill a été installé avant l&#39;ajout de la fonctionnalité de mise à jour. Vous devez le réinstaller une fois pour activer les mises à jour automatiques.</p></details><h3 id="etape-3-mettre-a-jour-des-skills-specifiques" tabindex="-1">Étape 3 : Mettre à Jour des Skills Spécifiques <a class="header-anchor" href="#etape-3-mettre-a-jour-des-skills-specifiques" aria-label="Permalink to &quot;Étape 3 : Mettre à Jour des Skills Spécifiques&quot;">​</a></h3><p>Si vous ne voulez mettre à jour que quelques skills spécifiques, passez les noms des skills (séparés par des virgules) :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-workflow,check-branch-first</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Seuls les deux skills spécifiés ont été mis à jour</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Summary: 2 updated, 0 skipped (2 total)</span></span></code></pre></div><h3 id="etape-4-mettre-a-jour-un-skill-en-developpement-local" tabindex="-1">Étape 4 : Mettre à Jour un Skill en Développement Local <a class="header-anchor" href="#etape-4-mettre-a-jour-un-skill-en-developpement-local" aria-label="Permalink to &quot;Étape 4 : Mettre à Jour un Skill en Développement Local&quot;">​</a></h3><p>Si vous développez un skill localement, vous pouvez le mettre à jour depuis le chemin local :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Le skill est recopié depuis le chemin local où vous l&#39;avez installé</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: my-skill</span></span>
<span class="line"><span>Summary: 1 updated, 0 skipped (1 total)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Flux de Travail de Développement Local</p><p>Processus de développement :</p><ol><li>Installer le skill : <code>openskills install ./my-skill</code></li><li>Modifier le code</li><li>Mettre à jour le skill : <code>openskills update my-skill</code></li><li>Synchroniser vers AGENTS.md : <code>openskills sync</code></li></ol></div><h3 id="etape-5-gerer-les-echecs-de-mise-a-jour" tabindex="-1">Étape 5 : Gérer les Échecs de Mise à Jour <a class="header-anchor" href="#etape-5-gerer-les-echecs-de-mise-a-jour" aria-label="Permalink to &quot;Étape 5 : Gérer les Échecs de Mise à Jour&quot;">​</a></h3><p>Si certains skills échouent à se mettre à jour, OpenSkills affichera les causes détaillées :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Situations possibles</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skipped: git-workflow (git clone failed)</span></span>
<span class="line"><span>Skipped: my-skill (local source missing)</span></span>
<span class="line"><span>Missing source metadata (1): old-skill</span></span>
<span class="line"><span>Clone failed (1): git-workflow</span></span></code></pre></div><p><strong>Méthodes de résolution correspondantes</strong> :</p><table tabindex="0"><thead><tr><th>Message d&#39;Erreur</th><th>Cause</th><th>Méthode de Résolution</th></tr></thead><tbody><tr><td><code>no source metadata</code></td><td>Installation de l&#39;ancienne version</td><td>Réinstaller : <code>openskills install &lt;source&gt;</code></td></tr><tr><td><code>local source missing</code></td><td>Le chemin local a été supprimé</td><td>Restaurer le chemin local ou réinstaller</td></tr><tr><td><code>SKILL.md missing at local source</code></td><td>Le fichier local a été supprimé</td><td>Restaurer le fichier SKILL.md</td></tr><tr><td><code>git clone failed</code></td><td>Problème réseau ou dépôt inexistant</td><td>Vérifier le réseau ou l&#39;adresse du dépôt</td></tr><tr><td><code>SKILL.md not found in repo</code></td><td>Changement de structure du dépôt</td><td>Contacter l&#39;auteur du skill ou mettre à jour le sous-chemin</td></tr></tbody></table><h2 id="point-de-controle-✅" tabindex="-1">Point de Contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de Contrôle ✅&quot;">​</a></h2><p>Confirmez que vous avez appris :</p><ul><li>[ ] Savoir utiliser <code>openskills update</code> pour mettre à jour tous les skills</li><li>[ ] Savoir mettre à jour des skills spécifiques en les séparant par des virgules</li><li>[ ] Comprendre la signification et la résolution des skills &quot;ignorés&quot;</li><li>[ ] Connaître le flux de mise à jour pour les skills en développement local</li></ul><h2 id="mises-en-garde" tabindex="-1">Mises en Garde <a class="header-anchor" href="#mises-en-garde" aria-label="Permalink to &quot;Mises en Garde&quot;">​</a></h2><h3 id="❌-erreurs-courantes" tabindex="-1">❌ Erreurs Courantes <a class="header-anchor" href="#❌-erreurs-courantes" aria-label="Permalink to &quot;❌ Erreurs Courantes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Erreur</th><th>Bonne Pratique</th></tr></thead><tbody><tr><td>Ignorer les skills qui sont ignorés</td><td>Réinstaller ou corriger le problème selon les indications</td></tr><tr><td>Supprimer et réinstaller à chaque fois</td><td>Utiliser la commande <code>update</code> pour plus d&#39;efficacité</td></tr><tr><td>Ne pas savoir d&#39;où le skill a été installé</td><td>Utiliser <code>openskills list</code> pour voir la source</td></tr></tbody></table><h3 id="⚠️-points-d-attention" tabindex="-1">⚠️ Points d&#39;Attention <a class="header-anchor" href="#⚠️-points-d-attention" aria-label="Permalink to &quot;⚠️ Points d&#39;Attention&quot;">​</a></h3><p><strong>La mise à jour écrasera les modifications locales</strong></p><p>Si vous avez directement modifié les fichiers du skill dans le répertoire d&#39;installation, ces modifications seront écrasées lors de la mise à jour. La bonne pratique est :</p><ol><li>Modifier les <strong>fichiers sources</strong> (chemin local ou dépôt)</li><li>Puis exécuter <code>openskills update</code></li></ol><p><strong>Les skills installés par lien symbolique nécessitent un traitement spécial</strong></p><p>Si le skill a été installé via un lien symbolique (voir <a href="./../../advanced/symlink-support/">Support des Liens Symboliques</a>), la mise à jour recréera le lien sans briser la relation de lien symbolique.</p><p><strong>Les skills globaux et par projet doivent être mis à jour séparément</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mettre à jour uniquement les skills du projet (par défaut)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># La mise à jour des skills globaux nécessite un traitement séparé</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ou utiliser le mode --universal pour une gestion unifiée</span></span></code></pre></div><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la Leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la Leçon&quot;">​</a></h2><p>Dans cette leçon, nous avons appris la fonctionnalité de mise à jour d&#39;OpenSkills :</p><ul><li><strong>Mise à jour par lots</strong> : <code>openskills update</code> met à jour tous les skills en un clic</li><li><strong>Mise à jour spécifique</strong> : <code>openskills update skill1,skill2</code> met à jour des skills spécifiques</li><li><strong>Sensibilité à la source</strong> : Reconnaissance automatique des chemins locaux et des dépôts git</li><li><strong>Messages d&#39;erreur</strong> : Explication détaillée des raisons des skills ignorés et des méthodes de résolution</li></ul><p>La fonctionnalité de mise à jour permet aux skills de rester à la dernière version, garantissant que les skills que vous utilisez contiennent toujours les dernières améliorations et corrections.</p><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la Prochaine Leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la Prochaine Leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../remove-skills/">Supprimer des Skills</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment utiliser la commande interactive <code>manage</code> pour supprimer des skills</li><li>Comment utiliser la commande <code>remove</code> pour des suppressions scriptées</li><li>Les points d&#39;attention après avoir supprimé des skills</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du Code Source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du Code Source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du Fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Logique principale de mise à jour des skills</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L14-L150" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>14-150</td></tr><tr><td>Mise à jour depuis le chemin local</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L64-L82" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>64-82</td></tr><tr><td>Mise à jour depuis le dépôt Git</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L85-L125" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>85-125</td></tr><tr><td>Copier le skill depuis le répertoire</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L152-L163" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>152-163</td></tr><tr><td>Vérification de sécurité du chemin</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L165-L172" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>165-172</td></tr><tr><td>Définition de la structure des métadonnées</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L8-L15" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>8-15</td></tr><tr><td>Lecture des métadonnées du skill</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L17-L27" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>17-27</td></tr><tr><td>Écriture des métadonnées du skill</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L29-L36" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>29-36</td></tr><tr><td>Définition des commandes CLI</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/cli.ts#L58-L62" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>58-62</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>SKILL_METADATA_FILE = &#39;.openskills.json&#39;</code> : Nom du fichier de métadonnées, enregistre la source d&#39;installation du skill</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>updateSkills(skillNames)</code> : Fonction principale pour mettre à jour des skills spécifiques ou tous les skills</li><li><code>updateSkillFromDir(targetPath, sourceDir)</code> : Copier le skill depuis le répertoire source vers le répertoire cible</li><li><code>isPathInside(targetPath, targetDir)</code> : Vérifier la sécurité du chemin d&#39;installation (empêcher le parcours de chemin)</li><li><code>readSkillMetadata(skillDir)</code> : Lire les métadonnées du skill</li><li><code>writeSkillMetadata(skillDir, metadata)</code> : Écrire/mettre à jour les métadonnées du skill</li></ul><p><strong>Règles métier</strong> :</p><ul><li><strong>BR-5-1</strong> : Par défaut, mettre à jour tous les skills installés (update.ts:37-38)</li><li><strong>BR-5-2</strong> : Prend en charge les listes de noms de skills séparés par des virgules (update.ts:15)</li><li><strong>BR-5-3</strong> : Ignorer les skills sans métadonnées de source (update.ts:56-62)</li><li><strong>BR-5-4</strong> : Prend en charge la mise à jour depuis le chemin local (update.ts:64-82)</li><li><strong>BR-5-5</strong> : Prend en charge la mise à jour depuis le dépôt git (update.ts:85-125)</li><li><strong>BR-5-6</strong> : Vérifier la sécurité du chemin (update.ts:156-162)</li></ul></details>`,75)])])}const m=s(a,[["render",r]]);export{h as __pageData,m as default};
